   475→        .stage_providers
   476→        .get(next_stage)
   477→        .cloned()
   478→        .unwrap_or_else(|| meta.provider_chain.first().cloned().unwrap_or_default());
   479→    let provider_chain = if next_provider.is_empty() {
   480→        meta.provider_chain.clone()
   481→    } else {
   482→        // Put stage-specific provider first, rest as fallback
   483→        let mut chain = vec![next_provider];
   484→        for p in &meta.provider_chain {
   485→            if !chain.contains(p) {
