    18→pub fn next_run_id(pid: Option<u32>) -> String {
    19→    let ts = Utc::now()
    20→        .timestamp_nanos_opt()
    21→        .unwrap_or_else(|| Utc::now().timestamp_micros() * 1000);
    22→    format!("{}-{}", ts, pid.unwrap_or(0))
    23→}
