    25→pub fn pid_is_alive_sync(pid: i32) -> bool {
    26→    StdCommand::new("kill")
    27→        .arg("-0")
    28→        .arg(pid.to_string())
    29→        .status()
    30→        .map(|s| s.success())
    31→        .unwrap_or(false)
    32→}
