    34→pub fn append_log_line(path: &Path, line: &str) -> anyhow::Result<()> {
    35→    let mut file = fs::OpenOptions::new()
    36→        .create(true)
    37→        .append(true)
    38→        .open(path)?;
    39→    writeln!(file, "{}", line)?;
    40→    Ok(())
    41→}
