    43→pub fn copy_dir_all(src: &Path, dst: &Path) -> anyhow::Result<()> {
    44→    fs::create_dir_all(dst)?;
    45→    for entry in WalkDir::new(src).min_depth(1) {
    46→        let entry = entry?;
    47→        let rel = entry.path().strip_prefix(src)?;
    48→        let target = dst.join(rel);
    49→        if entry.file_type().is_dir() {
    50→            fs::create_dir_all(&target)?;
    51→        } else if entry.file_type().is_file() {
    52→            if let Some(parent) = target.parent() {
    53→                fs::create_dir_all(parent)?;
    54→            }
    55→            fs::copy(entry.path(), &target)?;
    56→        }
    57→    }
    58→    Ok(())
    59→}
