    61→pub fn unique_failed_path(failed_dir: &Path, name: &str) -> PathBuf {
    62→    let direct = failed_dir.join(name);
    63→    if !direct.exists() {
    64→        return direct;
    65→    }
    66→    let stem = name.strip_suffix(".bop").unwrap_or(name);
    67→    let ts = Utc::now().timestamp_millis();
    68→    failed_dir.join(format!("{stem}-rejected-{ts}.bop"))
    69→}
