    83→pub fn current_stage_step_index(meta: &Meta) -> u32 {
    84→    if let Some(idx) = meta
    85→        .stage_chain
    86→        .iter()
    87→        .position(|stage| stage == &meta.stage)
    88→        .map(|i| i + 1)
    89→    {
    90→        idx as u32
    91→    } else {
    92→        meta.step_index.unwrap_or(1).max(1)
    93→    }
    94→}
