  1099→/// Returns None if the file doesn't exist, is empty, or has no non-empty lines.
  1100→fn last_nonempty_line_from_stderr(card_dir: &Path) -> Option<String> {
  1101→    let stderr_log = card_dir.join("logs").join("stderr.log");
  1102→    let content = fs::read_to_string(&stderr_log).ok()?;
  1103→
  1104→    let last_line = content
  1105→        .lines()
  1106→        .rev()
  1107→        .find(|line| !line.trim().is_empty())?
  1108→        .to_string();
  1109→
  1110→    // Truncate to 256 bytes (not characters, to match spec)
  1111→    if last_line.len() <= 256 {
  1112→        Some(last_line)
  1113→    } else {
  1114→        // Find a valid UTF-8 boundary at or before 256 bytes
  1115→        let mut truncated = &last_line.as_bytes()[..256];
  1116→        while !std::str::from_utf8(truncated).is_ok() && !truncated.is_empty() {
  1117→            truncated = &truncated[..truncated.len() - 1];
  1118→        }
  1119→        std::str::from_utf8(truncated).ok().map(|s| s.to_string())
  1120→    }
  1121→}
