    20→pub fn scan_cards_for_cleanup(root: &Path, failed_age_days: u32) -> anyhow::Result<ScanResult> {
    21→    let states = vec!["drafts", "pending", "running", "done", "failed", "merged"];
    22→    let mut result = ScanResult::default();
    23→
    24→    for state in &states {
    25→        scan_state_dir_for_cleanup(root, state, failed_age_days, &mut result)?;
    26→
    27→        // Also scan team-* directories
    28→        if let Ok(entries) = fs::read_dir(root) {
